// Dashboard.js - Updated with real-time charts based on input values
import React, { useState, useEffect } from 'react';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend,
  ArcElement
} from 'chart.js';
import { Bar, Doughnut } from 'react-chartjs-2';
import './Dashboard.css';

// Register Chart.js components
ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend,
  ArcElement
);

function Dashboard({ dashboardData }) {
  const [activeTab, setActiveTab] = useState('overview');
  const [chartData, setChartData] = useState(null);

  useEffect(() => {
    if (dashboardData && dashboardData.individualResult) {
      generateChartData();
    }
  }, [dashboardData]);

  const generateChartData = () => {
    const apiData = dashboardData.individualResult || {};
    const customerData = apiData.customer_data || {};
    
    // Get current customer values
    const satisfactionScore = customerData.SatisfactionScore || 3;
    const hasComplaint = customerData.Complain || 0;
    const cityTier = customerData.CityTier || 1;
    const churnProbability = apiData.probability || 0.5;
    const tenure = customerData.Tenure || 5;
    const daysSinceLastOrder = customerData.DaySinceLastOrder || 7;
    const orderCount = customerData.OrderCount || 5;
    const cashbackAmount = customerData.CashbackAmount || 12000;

    // Calculate real-time data based on current customer profile
    const data = {
      // Chart 1: Current Customer Churn Probability (LEFT - PIE CHART)
      churnDistribution: {
        labels: ['Retention Probability', 'Churn Probability'],
        datasets: [
          {
            data: [
              Math.round((1 - churnProbability) * 100), // Retention %
              Math.round(churnProbability * 100) // Churn %
            ],
            backgroundColor: [
              '#10b981', // Green for retention
              '#ef4444'  // Red for churn
            ],
            borderColor: [
              '#059669',
              '#dc2626'
            ],
            borderWidth: 3,
            hoverOffset: 20
          }
        ]
      },

      // Chart 2: Churn Rate by Complaint Status (RIGHT - BAR CHART)
      churnByComplaint: {
        labels: ['No Complaint', 'With Complaint'],
        datasets: [
          {
            label: 'Churn Probability',
            data: hasComplaint === 1 ? 
              [0, 0.85] : // If complaint, show only complaint bar
              [0.15, 0],  // If no complaint, show only no complaint bar
            backgroundColor: [
              hasComplaint === 0 ? 'rgba(16, 185, 129, 0.8)' : 'rgba(16, 185, 129, 0.2)',
              hasComplaint === 1 ? 'rgba(239, 68, 68, 0.8)' : 'rgba(239, 68, 68, 0.2)'
            ],
            borderColor: [
              '#10b981',
              '#ef4444'
            ],
            borderWidth: hasComplaint === 0 ? [3, 1] : [1, 3]
          }
        ]
      },

      // Chart 3: Churn Rate by Satisfaction Score (RIGHT - BAR CHART)
      churnBySatisfaction: {
        labels: ['Score 1', 'Score 2', 'Score 3', 'Score 4', 'Score 5'],
        datasets: [
          {
            label: 'Churn Rate',
            data: [
              satisfactionScore === 1 ? 0.80 : 0,
              satisfactionScore === 2 ? 0.60 : 0,
              satisfactionScore === 3 ? 0.30 : 0,
              satisfactionScore === 4 ? 0.15 : 0,
              satisfactionScore === 5 ? 0.05 : 0
            ],
            backgroundColor: [
              satisfactionScore === 1 ? 'rgba(239, 68, 68, 0.8)' : 'rgba(239, 68, 68, 0.2)',
              satisfactionScore === 2 ? 'rgba(245, 158, 11, 0.8)' : 'rgba(245, 158, 11, 0.2)',
              satisfactionScore === 3 ? 'rgba(234, 179, 8, 0.8)' : 'rgba(234, 179, 8, 0.2)',
              satisfactionScore === 4 ? 'rgba(101, 163, 13, 0.8)' : 'rgba(101, 163, 13, 0.2)',
              satisfactionScore === 5 ? 'rgba(16, 185, 129, 0.8)' : 'rgba(16, 185, 129, 0.2)'
            ],
            borderColor: [
              '#ef4444',
              '#f59e0b',
              '#eab308',
              '#65a30d',
              '#10b981'
            ],
            borderWidth: [
              satisfactionScore === 1 ? 3 : 1,
              satisfactionScore === 2 ? 3 : 1,
              satisfactionScore === 3 ? 3 : 1,
              satisfactionScore === 4 ? 3 : 1,
              satisfactionScore === 5 ? 3 : 1
            ]
          }
        ]
      },

      // Chart 4: Churn Rate by City Tier (LEFT - BAR CHART)
      churnByCityTier: {
        labels: ['Tier 1', 'Tier 2', 'Tier 3'],
        datasets: [
          {
            label: 'Churn Rate',
            data: [
              cityTier === 1 ? 0.18 : 0,
              cityTier === 2 ? 0.22 : 0,
              cityTier === 3 ? 0.25 : 0
            ],
            backgroundColor: [
              cityTier === 1 ? 'rgba(59, 130, 246, 0.8)' : 'rgba(59, 130, 246, 0.2)',
              cityTier === 2 ? 'rgba(139, 92, 246, 0.8)' : 'rgba(139, 92, 246, 0.2)',
              cityTier === 3 ? 'rgba(16, 185, 129, 0.8)' : 'rgba(16, 185, 129, 0.2)'
            ],
            borderColor: [
              '#3b82f6',
              '#8b5cf6',
              '#10b981'
            ],
            borderWidth: [
              cityTier === 1 ? 3 : 1,
              cityTier === 2 ? 3 : 1,
              cityTier === 3 ? 3 : 1
            ]
          }
        ]
      },

      // Additional Chart: Key Metrics Impact (Real-time)
      keyMetrics: {
        labels: ['Tenure (months)', 'Days Since Order', 'Order Count', 'Cashback (₹k)'],
        datasets: [
          {
            label: 'Current Value',
            data: [
              Math.min(tenure / 24, 1), // Normalize tenure (24 months = 100%)
              Math.min(daysSinceLastOrder / 60, 1), // Normalize days (60 days = 100%)
              Math.min(orderCount / 20, 1), // Normalize order count (20 orders = 100%)
              Math.min(cashbackAmount / 20000, 1) // Normalize cashback (20k = 100%)
            ],
            backgroundColor: 'rgba(59, 130, 246, 0.6)',
            borderColor: '#3b82f6',
            borderWidth: 2
          },
          {
            label: 'Ideal Range',
            data: [0.5, 0.12, 0.5, 0.6], // Ideal benchmarks
            backgroundColor: 'rgba(16, 185, 129, 0.4)',
            borderColor: '#10b981',
            borderWidth: 2
          }
        ]
      }
    };
    
    setChartData(data);
  };

  // Chart options with increased heights
  const doughnutOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'bottom',
        labels: {
          font: {
            size: 14,
            family: "'Inter', sans-serif",
            weight: '600'
          },
          padding: 25,
          usePointStyle: true,
        }
      },
      title: {
        display: true,
        text: 'Customer Churn Probability Distribution',
        font: {
          size: 18,
          weight: 'bold',
          family: "'Inter', sans-serif"
        },
        padding: 20
      },
      tooltip: {
        backgroundColor: 'rgba(0, 0, 0, 0.8)',
        titleFont: {
          size: 14,
          weight: 'bold'
        },
        bodyFont: {
          size: 13
        },
        padding: 12,
        cornerRadius: 8,
        callbacks: {
          label: function(context) {
            const label = context.label || '';
            const value = context.raw || 0;
            return `${label}: ${value}%`;
          }
        }
      }
    },
    cutout: '45%'
  };

  const barOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        display: false,
      },
      title: {
        display: true,
        font: {
          size: 18,
          weight: 'bold',
          family: "'Inter', sans-serif"
        },
        padding: 20
      },
      tooltip: {
        backgroundColor: 'rgba(0, 0, 0, 0.8)',
        titleFont: {
          size: 14,
          weight: 'bold'
        },
        bodyFont: {
          size: 13
        },
        padding: 12,
        cornerRadius: 8,
        callbacks: {
          label: function(context) {
            if (context.raw > 0) {
              return `Churn Rate: ${(context.raw * 100).toFixed(1)}%`;
            }
            return 'No data for current selection';
          }
        }
      }
    },
    scales: {
      y: {
        beginAtZero: true,
        max: 1.0,
        ticks: {
          callback: function(value) {
            return (value * 100).toFixed(0) + '%';
          },
          font: {
            family: "'Inter', sans-serif",
            size: 12,
            weight: '600'
          },
          padding: 10
        },
        title: {
          display: true,
          text: 'Churn Rate (%)',
          font: {
            family: "'Inter', sans-serif",
            size: 14,
            weight: 'bold'
          },
          padding: 10
        },
        grid: {
          color: 'rgba(0, 0, 0, 0.1)',
          drawBorder: false
        }
      },
      x: {
        ticks: {
          font: {
            family: "'Inter', sans-serif",
            size: 13,
            weight: '600'
          },
          padding: 10
        },
        grid: {
          display: false
        }
      }
    }
  };

  const metricsOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          font: {
            size: 12,
            family: "'Inter', sans-serif",
            weight: '600'
          }
        }
      },
      title: {
        display: true,
        text: 'Key Customer Metrics vs Ideal Range',
        font: {
          size: 18,
          weight: 'bold',
          family: "'Inter', sans-serif"
        },
        padding: 20
      }
    },
    scales: {
      y: {
        beginAtZero: true,
        max: 1.0,
        ticks: {
          callback: function(value) {
            return (value * 100).toFixed(0) + '%';
          },
          font: {
            family: "'Inter', sans-serif"
          }
        },
        title: {
          display: true,
          text: 'Normalized Score'
        }
      }
    }
  };

  if (!dashboardData) {
    return (
      <div className="dashboard">
        <div className="dashboard-header">
          <h2>Churn Analysis Dashboard</h2>
        </div>
        <div className="dashboard-placeholder">
          <div className="placeholder-content">
            <span className="placeholder-icon">🔍</span>
            <h3>No Analysis Data Available</h3>
            <p>Run a customer analysis to view insights and predictions</p>
          </div>
        </div>
      </div>
    );
  }

  // Extract data from API response
  const apiData = dashboardData.individualResult || {};
  const customerData = apiData.customer_data || {};
  
  const currentChurnProbability = Math.round((apiData.probability || 0) * 100);
  const currentSatisfaction = customerData.SatisfactionScore || 'Not set';
  const hasComplaint = customerData.Complain === 1 ? 'Yes' : 'No';
  const cityTier = customerData.CityTier || 'Not set';
  const tenure = customerData.Tenure || 0;
  const daysSinceLastOrder = customerData.DaySinceLastOrder || 0;
  const orderCount = customerData.OrderCount || 0;
  const cashbackAmount = customerData.CashbackAmount || 0;

  // Chart Components
  const ChurnDistributionChart = () => {
    if (!chartData) return <div className="chart-loading">Loading churn distribution...</div>;
    
    return (
      <div className="chart-card large-chart">
        <div className="chart-header">
          <h3>Customer Churn Probability</h3>
          <span className="chart-subtitle">ML Model Prediction Distribution</span>
        </div>
        <div className="chart-container-large">
          <Doughnut data={chartData.churnDistribution} options={doughnutOptions} />
        </div>
        <div className="chart-footer">
          <div className="probability-breakdown">
            <div className="breakdown-item retention">
              <span className="breakdown-label">Retention Probability</span>
              <span className="breakdown-value">{Math.round((1 - (apiData.probability || 0)) * 100)}%</span>
            </div>
            <div className="breakdown-item churn">
              <span className="breakdown-label">Churn Probability</span>
              <span className="breakdown-value">{currentChurnProbability}%</span>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const ChurnByComplaintChart = () => {
    if (!chartData) return <div className="chart-loading">Loading complaint analysis...</div>;
    
    const options = {
      ...barOptions,
      plugins: {
        ...barOptions.plugins,
        title: {
          ...barOptions.plugins.title,
          text: 'Impact of Customer Complaints on Churn Rate'
        }
      }
    };

    return (
      <div className="chart-card large-chart">
        <div className="chart-header">
          <h3>Complaint Impact Analysis</h3>
          <span className="chart-subtitle">
            Current customer: {hasComplaint === 'Yes' ? 'Has Complaint' : 'No Complaints'}
          </span>
        </div>
        <div className="chart-container-large">
          <Bar data={chartData.churnByComplaint} options={options} />
        </div>
        <div className="chart-footer">
          <div className="impact-stats">
            {hasComplaint === 'Yes' ? (
              <>
                <div className="impact-stat highlight">
                  <span className="impact-value">85%</span>
                  <span className="impact-label">Churn Risk with Complaint</span>
                </div>
                <div className="impact-stat">
                  <span className="impact-value">5.7x</span>
                  <span className="impact-label">Higher than Average</span>
                </div>
              </>
            ) : (
              <>
                <div className="impact-stat positive">
                  <span className="impact-value">15%</span>
                  <span className="impact-label">Churn Risk without Complaint</span>
                </div>
                <div className="impact-stat">
                  <span className="impact-value">Low</span>
                  <span className="impact-label">Complaint Risk</span>
                </div>
              </>
            )}
          </div>
        </div>
      </div>
    );
  };

  const ChurnBySatisfactionChart = () => {
    if (!chartData) return <div className="chart-loading">Loading satisfaction analysis...</div>;
    
    const options = {
      ...barOptions,
      plugins: {
        ...barOptions.plugins,
        title: {
          ...barOptions.plugins.title,
          text: 'Satisfaction Score Impact on Churn Rate'
        }
      }
    };

    return (
      <div className="chart-card large-chart">
        <div className="chart-header">
          <h3>Satisfaction Score Impact</h3>
          <span className="chart-subtitle">Current customer score: {currentSatisfaction}/5</span>
        </div>
        <div className="chart-container-large">
          <Bar data={chartData.churnBySatisfaction} options={options} />
        </div>
        <div className="chart-footer">
          <div className="satisfaction-insights">
            {currentSatisfaction <= 2 ? (
              <p className="warning-text"><strong>High Risk:</strong> Low satisfaction significantly increases churn probability</p>
            ) : currentSatisfaction <= 3 ? (
              <p className="warning-text"><strong>Moderate Risk:</strong> Average satisfaction requires monitoring</p>
            ) : (
              <p className="positive-text"><strong>Low Risk:</strong> High satisfaction reduces churn probability</p>
            )}
          </div>
        </div>
      </div>
    );
  };

  const ChurnByCityTierChart = () => {
    if (!chartData) return <div className="chart-loading">Loading city tier analysis...</div>;
    
    const options = {
      ...barOptions,
      plugins: {
        ...barOptions.plugins,
        title: {
          ...barOptions.plugins.title,
          text: 'Churn Rate by City Tier'
        }
      }
    };

    return (
      <div className="chart-card large-chart">
        <div className="chart-header">
          <h3>City Tier Analysis</h3>
          <span className="chart-subtitle">Current customer: Tier {cityTier}</span>
        </div>
        <div className="chart-container-large">
          <Bar data={chartData.churnByCityTier} options={options} />
        </div>
        <div className="chart-footer">
          <div className="city-tier-stats">
            <div className="tier-stat">
              <span className="tier-value">Tier {cityTier}</span>
              <span className="tier-label">Current Customer</span>
            </div>
            <div className="tier-stat">
              <span className="tier-risk">
                {cityTier == 1 ? 'Low' : cityTier == 2 ? 'Medium' : 'High'} Risk
              </span>
              <span className="tier-label">Churn Risk Level</span>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const KeyMetricsChart = () => {
    if (!chartData) return <div className="chart-loading">Loading metrics analysis...</div>;

    return (
      <div className="chart-card full-width">
        <div className="chart-header">
          <h3>Key Customer Metrics vs Ideal Range</h3>
          <span className="chart-subtitle">Current performance across critical dimensions</span>
        </div>
        <div className="chart-container-large">
          <Bar data={chartData.keyMetrics} options={metricsOptions} />
        </div>
        <div className="chart-footer">
          <div className="metrics-summary">
            <div className="metric-item">
              <span className="metric-name">Tenure:</span>
              <span className="metric-value">{tenure} months</span>
            </div>
            <div className="metric-item">
              <span className="metric-name">Last Order:</span>
              <span className="metric-value">{daysSinceLastOrder} days ago</span>
            </div>
            <div className="metric-item">
              <span className="metric-name">Total Orders:</span>
              <span className="metric-value">{orderCount}</span>
            </div>
            <div className="metric-item">
              <span className="metric-name">Cashback:</span>
              <span className="metric-value">₹{cashbackAmount}</span>
            </div>
          </div>
        </div>
      </div>
    );
  };

  // Enhanced Overview Tab
  const renderOverview = () => (
    <div className="overview-tab-enhanced">
      <div className="overview-content">
        <div className="welcome-section">
          <h2>Customer Churn Analysis Dashboard</h2>
          <p>Real-time ML-powered churn prediction and risk analysis</p>
        </div>
        
        <div className="quick-stats-overview">
          <div className="stat-card-overview">
            <div className="stat-icon">🎯</div>
            <div className="stat-content">
              <h3>Churn Probability</h3>
              <div className="stat-value">{currentChurnProbability}%</div>
              <div className="stat-description">ML Model Prediction</div>
            </div>
          </div>
          
          <div className="stat-card-overview">
            <div className="stat-icon">⭐</div>
            <div className="stat-content">
              <h3>Satisfaction</h3>
              <div className="stat-value">{currentSatisfaction}/5</div>
              <div className="stat-description">Current Score</div>
            </div>
          </div>
          
          <div className="stat-card-overview">
            <div className="stat-icon">⚠️</div>
            <div className="stat-content">
              <h3>Complaints</h3>
              <div className="stat-value">{hasComplaint}</div>
              <div className="stat-description">Filed Complaints</div>
            </div>
          </div>
          
          <div className="stat-card-overview">
            <div className="stat-icon">🏙️</div>
            <div className="stat-content">
              <h3>City Tier</h3>
              <div className="stat-value">{cityTier}</div>
              <div className="stat-description">Current Tier</div>
            </div>
          </div>
        </div>

        <div className="overview-actions">
          <button 
            className="btn primary large"
            onClick={() => setActiveTab('detailed')}
          >
            View Detailed Analysis →
          </button>
        </div>
      </div>
    </div>
  );

  // Detailed Analysis Tab with New Layout
  const renderDetailedAnalysis = () => (
    <div className="detailed-analysis-tab">
      <div className="analysis-header">
        <h2>Detailed Churn Analysis</h2>
        <p>Real-time insights based on current customer profile values</p>
        <div className="current-profile-badge">
          <span>Churn Risk: <strong>{currentChurnProbability}%</strong></span>
          <span>Satisfaction: <strong>{currentSatisfaction}/5</strong></span>
          <span>Complaints: <strong>{hasComplaint}</strong></span>
          <span>City Tier: <strong>{cityTier}</strong></span>
        </div>
      </div>
      
      {/* First Row: Pie Chart (Left) and Complaint Impact (Right) */}
      <div className="analysis-row-large">
        <div className="analysis-column-half">
          <ChurnDistributionChart />
        </div>
        <div className="analysis-column-half">
          <ChurnByComplaintChart />
        </div>
      </div>

      {/* Second Row: City Tier (Left) and Satisfaction (Right) */}
      <div className="analysis-row-large">
        <div className="analysis-column-half">
          <ChurnByCityTierChart />
        </div>
        <div className="analysis-column-half">
          <ChurnBySatisfactionChart />
        </div>
      </div>

      {/* Third Row: Key Metrics (Full Width) */}
      <div className="analysis-row-full">
        <KeyMetricsChart />
      </div>

      <div className="analysis-insights">
        <h3>Real-time Risk Assessment</h3>
        <div className="insights-grid">
          <div className={`insight-card ${currentChurnProbability > 70 ? 'critical' : currentChurnProbability > 30 ? 'warning' : 'positive'}`}>
            <div className="insight-icon">
              {currentChurnProbability > 70 ? '🚨' : currentChurnProbability > 30 ? '⚠️' : '✅'}
            </div>
            <div className="insight-content">
              <h4>Overall Risk Level</h4>
              <p>
                {currentChurnProbability > 70 
                  ? `HIGH RISK (${currentChurnProbability}%): Immediate intervention required. Focus on satisfaction improvement and complaint resolution.`
                  : currentChurnProbability > 30
                  ? `MODERATE RISK (${currentChurnProbability}%): Proactive monitoring recommended. Key factors: ${hasComplaint === 'Yes' ? 'Complaint' : 'No complaint'}, Satisfaction ${currentSatisfaction}/5`
                  : `LOW RISK (${currentChurnProbability}%): Maintain current engagement. Customer shows healthy behavior patterns.`
                }
              </p>
            </div>
          </div>
          
          <div className="insight-card info">
            <div className="insight-icon">📊</div>
            <div className="insight-content">
              <h4>Top Risk Factors</h4>
              <p>
                {hasComplaint === 'Yes' && '• Complaint Filed (High Impact) '}
                {currentSatisfaction <= 2 && '• Low Satisfaction Score '}
                {cityTier == 3 && '• Tier 3 City '}
                {daysSinceLastOrder > 30 && '• High Recency '}
                {orderCount < 3 && '• Low Order Count '}
                {!hasComplaint && currentSatisfaction > 3 && cityTier == 1 && '• All factors within acceptable ranges'}
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <div className="header-main">
          <h2>Churn Analysis Dashboard</h2>
          <p>Real-time ML-powered customer churn prediction and insights</p>
        </div>
        <div className="header-actions">
          <button className="btn secondary">Export PDF Report</button>
          <button className="btn primary">Save Analysis</button>
        </div>
      </div>

      <div className="dashboard-nav">
        <div className="nav-tabs">
          <button 
            className={`nav-button ${activeTab === 'overview' ? 'active' : ''}`}
            onClick={() => setActiveTab('overview')}
          >
            📊 Overview
          </button>
          <button 
            className={`nav-button ${activeTab === 'detailed' ? 'active' : ''}`}
            onClick={() => setActiveTab('detailed')}
          >
            🔍 Detailed Analysis
          </button>
        </div>
      </div>

      <div className="tab-content">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'detailed' && renderDetailedAnalysis()}
      </div>
    </div>
  );
}

export default Dashboard;
